CREATE TABLE customers (id INTEGER, name TEXT);
CREATE TABLE orders (id INTEGER, customer_id INTEGER, total REAL);

INSERT INTO customers VALUES (1, 'Alice'), (2, 'Bob'), (3, 'Carol');
INSERT INTO orders VALUES (1, 1, 50.00), (2, 1, 120.00), (3, 2, 30.00);

SELECT customers.name, orders.total
FROM orders
INNER JOIN customers ON orders.customer_id = customers.id
ORDER BY customers.name, orders.total;

CREATE TABLE customers (id INTEGER, name TEXT);
CREATE TABLE orders (id INTEGER, customer_id INTEGER, total REAL);

INSERT INTO customers VALUES (1, 'Alice'), (2, 'Bob'), (3, 'Carol');
INSERT INTO orders VALUES (1, 1, 50.00), (2, 2, 30.00);

SELECT c.name, COALESCE(o.total, 0) AS total
FROM customers c
LEFT JOIN orders o ON o.customer_id = c.id
ORDER BY c.name;

CREATE TABLE authors (id INTEGER, name TEXT);
CREATE TABLE books (id INTEGER, author_id INTEGER, title TEXT);
CREATE TABLE sales (book_id INTEGER, copies INTEGER);

INSERT INTO authors VALUES (1, 'Alice Author'), (2, 'Bob Writer');
INSERT INTO books VALUES (1, 1, 'TypeScript Guide'), (2, 1, 'SQL Mastery'), (3, 2, 'Go Handbook');
INSERT INTO sales VALUES (1, 500), (2, 1200), (3, 350);

SELECT a.name, b.title, s.copies
FROM books b
JOIN authors a ON b.author_id = a.id
JOIN sales s ON s.book_id = b.id
ORDER BY s.copies DESC;
